import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  Paper,
  Autocomplete,
  TextField,
} from "@mui/material";
import { useEffect, useState } from "react";
import API from "../../api/axios";

export default function OrganizationUsers() {
  const [orgs, setOrgs] = useState([]);
  const [users, setUsers] = useState([]);

  // Fetch organizations
  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    const orgRes = await API.get("organizations/");
    const userRes = await API.get("users/");
    setOrgs(orgRes.data);
    setUsers(userRes.data);
  };

  // Handle user assign
  const handleUserAssign = async (orgId, selectedUsers) => {
    await API.post(`assign-users/${orgId}/`, {
      users: selectedUsers.map((u) => u.username || u),
    });
  };

  return (
    <Paper sx={{ padding: 3 }}>
      <h2>Organization List</h2>

      <Table>
        <TableHead>
          <TableRow>
            <TableCell>
              <b>Organization Name</b>
            </TableCell>
            <TableCell>
              <b>Add User</b>
            </TableCell>
          </TableRow>
        </TableHead>

        <TableBody>
          {orgs.map((org) => (
            <TableRow key={org.id}>
              <TableCell>{org.name}</TableCell>

              <TableCell>
                <Autocomplete
                  multiple
                  freeSolo
                  options={users.map((u) => u.username)}
                  onChange={(e, value) => handleUserAssign(org.id, value)}
                  renderInput={(params) => (
                    <TextField {...params} placeholder="Add Users" />
                  )}
                />
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </Paper>
  );
}
